SELECT SUM(total_votes_cast) AS "Total Votes Cast"
FROM wards_total
WHERE election_id = 1;

SELECT candidate_name
FROM candidates
WHERE candidate_id IN (SELECT candidate_id FROM votes);

SELECT candidate_name, party_affiliation
FROM candidates
WHERE candidate_id = 1;

SELECT COUNT(DISTINCT city_id) AS unique_election_cities
FROM votes
WHERE count_status = 'complete';

SELECT AVG(CAST(voter_turnout AS REAL))
FROM wards
WHERE CAST(voter_turnout AS REAL) > 60;

SELECT representative_contact
FROM electoral_districts
WHERE district_name = 'District 1';
